WHERE 1 = 1

    AND mt.tech_type = #{techType}


    AND (
        mt.tech_code ILIKE CONCAT('%', #{keyword}, '%')
        OR mt.tech_name ILIKE CONCAT('%', #{keyword}, '%')
    )

